+// Unified database interface
+interface DbInterface {
+  run(sql: string, params?: any[]): { lastInsertRowid: number; changes: number };
+  get<T>(sql: string, params?: any[]): T | undefined;
+  all<T>(sql: string, params?: any[]): T[];
+  exec(sql: string): void;
+  close(): void;
+}
+
+// sql.js wrapper
+class SqlJsWrapper implements DbInterface {
+  private db: any;
+  private dbPath: string;
+  private saveTimeout: NodeJS.Timeout | null = null;
+
+  constructor(db: any, dbPath: string) {
+    this.db = db;
+    this.dbPath = dbPath;
+  }
+
+  private scheduleSave(): void {
+    if (this.saveTimeout) {
+      clearTimeout(this.saveTimeout);
+    }
+    this.saveTimeout = setTimeout(() => {
+      this.saveNow();
+    }, 100); // Debounce saves
+  }
+
+  private saveNow(): void {
+    try {
+      const data = this.db.export();
+      const buffer = Buffer.from(data);
+      writeFileSync(this.dbPath, buffer);
+    } catch {
+      // Ignore save errors
+    }
+  }
+
+  run(sql: string, params?: any[]): { lastInsertRowid: number; changes: number } {
+    this.db.run(sql, params || []);
+    const lastId = this.db.exec('SELECT last_insert_rowid() as id')[0]?.values[0]?.[0] || 0;
+    const changes = this.db.getRowsModified();
+    this.scheduleSave();
+    return { lastInsertRowid: lastId as number, changes };
+  }
+
+  get<T>(sql: string, params?: any[]): T | undefined {
+    const stmt = this.db.prepare(sql);
+    if (params) stmt.bind(params);
+    if (stmt.step()) {
+      const columns = stmt.getColumnNames();
+      const values = stmt.get();
+      stmt.free();
+      const result: any = {};
+      columns.forEach((col: string, i: number) => {
+        result[col] = values[i];
+      });
+      return result;
+    }
+    stmt.free();
+    return undefined;
+  }
+
+  all<T>(sql: string, params?: any[]): T[] {
+    const results: T[] = [];
+    const stmt = this.db.prepare(sql);
+    if (params) stmt.bind(params);
+    while (stmt.step()) {
+      const columns = stmt.getColumnNames();
+      const values = stmt.get();
+      const row: any = {};
+      columns.forEach((col: string, i: number) => {
+        row[col] = values[i];
+      });
+      results.push(row);
+    }
+    stmt.free();
+    return results;
+  }
+
+  exec(sql: string): void {
+    this.db.exec(sql);
+    this.scheduleSave();
+  }
+
+  close(): void {
+    if (this.saveTimeout) {
+      clearTimeout(this.saveTimeout);
+    }
+    this.saveNow();
+    this.db.close();
+  }
+}
+
+// better-sqlite3 wrapper
+class BetterSqliteWrapper implements DbInterface {
+  private db: any;
+
+  constructor(db: any) {
+    this.db = db;
+  }
+
+  run(sql: string, params?: any[]): { lastInsertRowid: number; changes: number } {
+    const stmt = this.db.prepare(sql);
+    const result = params ? stmt.run(...params) : stmt.run();
+    return { lastInsertRowid: result.lastInsertRowid as number, changes: result.changes };
+  }
+
+  get<T>(sql: string, params?: any[]): T | undefined {
+    const stmt = this.db.prepare(sql);
+    return params ? stmt.get(...params) : stmt.get();
+  }
+
+  all<T>(sql: string, params?: any[]): T[] {
+    const stmt = this.db.prepare(sql);
+    return params ? stmt.all(...params) : stmt.all();
+  }
+
+  exec(sql: string): void {
+    this.db.exec(sql);
+  }
+
+  close(): void {
+    this.db.close();
+  }
+}
